firmware_template.source:
#include "event_group.h"
static EventGroupHandle_t _eg=NULL;
void event_group_setup(){_eg=xEventGroupCreate();Serial.println("[events] OK");}
void event_set_bits(uint32_t b){xEventGroupSetBits(_eg,b);}
void event_clear_bits(uint32_t b){xEventGroupClearBits(_eg,b);}
uint32_t event_wait_bits(uint32_t b,bool all,uint32_t ms){return xEventGroupWaitBits(_eg,b,pdTRUE,all?pdTRUE:pdFALSE,ms/portTICK_PERIOD_MS);}
uint32_t event_get_bits(){return xEventGroupGetBits(_eg);}
